{"path":"src/db.rs","content":"use crate::api::*;
use crate::distance::l2_distance;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::cmp::Ordering;

pub struct VectorDB {
    ids: RwLock<Vec<u64>>,
    vectors: RwLock<Vec<f32>>, // Flattened for better cache locality
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            ids: RwLock::new(Vec::with_capacity(1_000_000)),
            vectors: RwLock::new(Vec::with_capacity(1_000_000 * 128)),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids = self.ids.write();
        let mut vectors = self.vectors.write();
        ids.push(id);
        vectors.extend(vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<InsertRequest>) -> usize {
        let count = vectors.len();
        let mut ids = self.ids.write();
        let mut vs = self.vectors.write();
        for req in vectors {
            ids.push(req.id);
            vs.extend(req.vector);
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read();
        let vectors = self.vectors.read();
        let n = ids.len();

        let mut results: Vec<SearchResult> = (0..n)
            .into_par_iter()
            .map(|i| {
                let start = i * 128;
                let v = &vectors[start..start + 128];
                SearchResult {
                    id: ids[i],
                    distance: l2_distance(v, vector),
                }
            })
            .collect();

        // Binary heap might be faster for top-k, but with 1M items, 
        // quickselect (select_nth_unstable) is very efficient.
        let k = (top_k as usize).min(n);
        if k < n {
            results.select_nth_unstable_by(k - 1, |a, b| {
                a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal)
            });
            results.truncate(k);
        }

        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
        results
    }
}
